import React, { useEffect, useRef, useState } from "react";
import {
  Container,
  CategoryRow,
  CategoryThumb,
  CategoryThumbPlaceholder,
  CategoryMeta,
  CategoryName,
  CategoryBadges,
  PriorityBadge,
  DiscountBadge,
  CategoriesContainer,
  AddCategory,
  Edit,
  Delete,
  Actions,
  BackIcon,
  AddCategoryForm,
  Tabs,
  Tab,
  categoryFormFieldSx,
  SectionHeader,
  SectionTitle,
  SectionSubtitle,
  EmptyState,
} from "./styles";
import { IoMdAdd } from "react-icons/io";
import { TextField, Button } from "@mui/material";
import { getCookie } from "../../../utilities/manageCookies";
import { LANGUAGES } from "../../../global";
import { LoadingButton } from "@mui/lab";
import { isEmpty, isNull } from "lodash";
import {
  EnArCategorySchema,
  arCategorySchema,
  enCategorySchema,
} from "./yup-shape";
import { useForm } from "react-hook-form";
import { yupResolver } from "@hookform/resolvers/yup";
import { useAddCategoryQuery } from "../../../apis/categories/addCategory";
import { useGetCategories } from "../../../apis/categories/getCategories";
import { useEditCategoryQuery } from "../../../apis/categories/editCategory";
import DeleteCategoryPopup from "./deleteCategoryPopup";
import { useGetProducts } from "../../../apis/products/getProducts";
import {
  UploadBtn,
  UploadImageText,
  UploadPhoto,
  UploadedImage,
} from "../products/addproduct/styles";
import { toast } from "react-toastify";
import ProductOptionsEditor, {
  optionsFromFormJsonString,
} from "../../../product-options/ProductOptionsEditor";
import { emptyOptions, serializeOptions } from "../../../product-options/schema";

const CATEGORY_IMAGE_BASE =
  "https://storage.googleapis.com/ecommerce-bucket-testing/";

export default function Categories({ setProducts }) {
  const [showAddComponent, setShowAddComponent] = useState(false);
  const [isDeletePopupOpen, setIsDeletePopupOpen] = useState(false);
  const { AR, ENAR, EN } = LANGUAGES;
  const storedUserInfo = getCookie("userInfo") || "{}";
  const [userInformation, _] = useState(JSON.parse(storedUserInfo));
  const [categories, setCategories] = useState([]);
  const [selectedIdForAction, setSelectedIdForAction] = useState(null);
  const [file, setFile] = useState(null);
  const [fileErrMsg, setFileErrMsg] = useState("Please upload image");
  const [activeTab, setActiveTab] = useState("categoryinfo")
  const [categoryOptions, setCategoryOptions] = useState(() => emptyOptions());
  const [imageUrl, setImageUrl] = useState(null);
  const fileInputRef = useRef(null);
  const { refetch: refetchProducts } = useGetProducts({
    onSuccess: () => { },
    restaurantId: userInformation.restaurant_id,
  });

  const schema =
    userInformation.Lang === AR
      ? arCategorySchema
      : userInformation.Lang === EN
        ? enCategorySchema
        : EnArCategorySchema;

  const displayEnglish =
    userInformation.Lang === EN || userInformation.Lang === ENAR;

  const displayArabic =
    userInformation.Lang === AR || userInformation.Lang === ENAR;

  const { handleSubmit, register, formState, setValue, reset, getValues } =
    useForm({
      resolver: yupResolver(schema),
    });
  const { isPending, handleApiCall } = useAddCategoryQuery({
    onSuccess: () => {
      refetchCategories();
      refetchProductsHandler();
      reset();
      setShowAddComponent(false);
      setFile(null);
      setImageUrl(null);
    },
    onError: () => {
      toast.error("Failed to add category !!");
    },
  });

  const { isPending: isEditing, handleApiCall: handleEditApi } =
    useEditCategoryQuery({
      onSuccess: () => {
        setShowAddComponent(false);
        refetchCategories();
        refetchProductsHandler();
        reset();
        setFile(null);
        setImageUrl(null);
        setSelectedIdForAction(null)
      },
      onError: () => {
        toast.error("Failed to add product !!");
      },
    });


  const { isLoading, response, refetch } = useGetCategories({
    onSuccess: () => { },
    restaurantId: userInformation.restaurant_id,
  });

  const handleAddCategory = () => {
    handleSubmit((data) => {
      let payload = {
        ...data,
        restaurant_id: userInformation.restaurant_id,
        image: file,
        form_json: serializeOptions(categoryOptions)
      };

      !selectedIdForAction
        ? handleApiCall(payload)
        : handleEditApi(selectedIdForAction, payload);
    })();
  };

  const handleOnEdit = (category) => {
    setValue("priority", category?.priority);
    setValue("discount", category?.discount);

    switch (userInformation.Lang) {
      case EN:
        setValue("en_category", category.en_category);

        break;
      case AR:
        setValue("ar_category", category.ar_category);

        break;
      case ENAR:
        setValue("en_category", category.en_category);
        setValue("ar_category", category.ar_category);
        break;
      default:
        break;
    }
    const opts = optionsFromFormJsonString(category?.form_json);
    setValue("form_json", serializeOptions(opts));
    setCategoryOptions(opts);

    setSelectedIdForAction(category.id);
    setShowAddComponent(true);
    setImageUrl(`${CATEGORY_IMAGE_BASE}${category?.image_url}`);
  };

  const refetchCategories = () => {
    refetch()
      .then(({ data: { data } }) => setCategories(data))
      .catch((err) => console.log(err));
  };
  function refetchProductsHandler() {
    refetchProducts()
      .then(({ data: { data } }) => setProducts(data))
      .catch((err) => console.log(err));
  }

  useEffect(() => {
    if (!isLoading) {
      setCategories(response?.data);
    }
  }, [isLoading]);

  useEffect(() => {
    if (showAddComponent && selectedIdForAction == null) {
      setCategoryOptions(emptyOptions());
    }
  }, [showAddComponent, selectedIdForAction]);

  const categoryText = (category) => {
    switch (userInformation.Lang) {
      case EN:
        return category.en_category;
      case AR:
        return category.ar_category;
      case ENAR:
        return `${category.en_category}-${category.ar_category}`;
      default:
        return category?.en_category || category?.ar_category || "";
    }
  };

  const handleButtonClick = () => {
    fileInputRef.current.click();
  };
  const handleOnDeleteImage = () => {
    setImageUrl(null);
    setFile(null);
    setValue("image", null);
  };
  const handleFileChange = ({ target }) => {
    if (target.files[0]) {
      const uploadedFile = target.files[0];
      const fileSizeInMB = uploadedFile.size / (1024 * 1024);
      if (fileSizeInMB > 4) {
        setFileErrMsg("Image is greater than 4MB");
        return;
      } else {
        setFileErrMsg("Please upload image");
      }
      setFile(target.files[0]);
      const url = URL.createObjectURL(target.files[0]);
      setImageUrl(url);
    }
    target.value = null;
  };

  return (
    <Container>
      <DeleteCategoryPopup
        isOpen={isDeletePopupOpen}
        setIsOpen={setIsDeletePopupOpen}
        selectedIdForAction={selectedIdForAction}
        refetchCategories={refetchCategories}
        setSelectedIdForAction={setSelectedIdForAction}
        refetchProductsHandler={refetchProductsHandler}
      />
      {showAddComponent ? (
        <AddCategoryForm activeTab={activeTab} >
          <BackIcon
            onClick={() => {
              reset();
              setShowAddComponent(false);
              setImageUrl(null);
              setFile(null);
              setSelectedIdForAction(null);
            }}
          />
          <Tabs>
            <Tab
              activeTab={activeTab}
              tab={"categoryinfo"}
              onClick={() => {
                setActiveTab("categoryinfo");
              }}
            >
              Category Details
            </Tab>
            <Tab
              activeTab={activeTab}
              tab={"formbuilder"}
              onClick={() => {
                setActiveTab("formbuilder");
              }}
            >
              Category options
            </Tab>
          </Tabs>
          {activeTab === "categoryinfo" ? (
            <>
              {displayEnglish && (
                <TextField
                  label="English category"
                  name="en_category"
                  variant="outlined"
                  {...register("en_category")}
                  fullWidth
                  sx={categoryFormFieldSx}
                  error={!isEmpty(formState?.errors?.en_category)}
                  helperText={
                    !isEmpty(formState?.errors?.en_category) &&
                    formState.errors?.en_category.message
                  }
                />
              )}
              {displayArabic && (
                <TextField
                  label="Arabic category"
                  name="ar_category"
                  variant="outlined"
                  {...register("ar_category")}
                  fullWidth
                  sx={categoryFormFieldSx}
                  error={!isEmpty(formState?.errors?.ar_category)}
                  helperText={
                    !isEmpty(formState?.errors?.ar_category) &&
                    formState.errors?.ar_category.message
                  }
                />
              )}
              <TextField
                label="Priority"
                name="priority"
                variant="outlined"
                {...register("priority")}
                fullWidth
                sx={categoryFormFieldSx}
                error={!isEmpty(formState?.errors?.priority)}
                helperText={
                  !isEmpty(formState?.errors?.priority) && "Required Field"
                }
                type="number"
                defaultValue={1}
                inputProps={{ min: 1 }}
              />
              <TextField
                label={"Discount"}
                name={"discount"}
                variant="outlined"
                {...register("discount")}
                fullWidth
                sx={categoryFormFieldSx}
                type="number"
              />
              <UploadPhoto
                type="file"
                ref={fileInputRef}
                onChange={handleFileChange}
              />
              {imageUrl ? (
                <Button
                  variant="contained"
                  color="error"
                  style={{ width: "150px", height: "40px" }}
                  onClick={() => handleOnDeleteImage()}
                >
                  Delete
                </Button>
              ) : (
                <UploadBtn onClick={handleButtonClick}>Upload Image</UploadBtn>
              )}
              {!imageUrl && !getValues().image && (
                <UploadImageText>{fileErrMsg}</UploadImageText>
              )}
              {imageUrl && <UploadedImage src={imageUrl} alt="Uploaded" />}
              <LoadingButton
                loading={isPending || isEditing}
                variant="contained"
                style={{ backgroundColor: "turquoise", height: "55px" }}
                onClick={handleAddCategory}
              >
                {!isNull(selectedIdForAction) ? "Edit Category" : "Add Category"}
              </LoadingButton>
            </>
          ) : (
              <ProductOptionsEditor
                value={categoryOptions}
                onChange={setCategoryOptions}
                languageHint={userInformation.Lang === AR ? "ar" : "en"}
              />
            )}
        </AddCategoryForm>
      ) : (
        <>
          {!isLoading && (
            <>
              <SectionHeader>
                <SectionTitle>Categories</SectionTitle>
                <SectionSubtitle>
                  Organize your menu into sections. Set priority, discounts, and
                  optional images—customers see categories on your public menu.
                </SectionSubtitle>
              </SectionHeader>
              <AddCategory onClick={() => setShowAddComponent(true)}>
                <IoMdAdd size={20} />
                Add Category
              </AddCategory>
              <CategoriesContainer>
                {categories?.length ? (
                  categories.map((category) => {
                    const label = categoryText(category) || "—";
                    const initial = (label || "?").trim().charAt(0);
                    const hasImage = Boolean(category?.image_url);
                    const discountNum = Number(category?.discount);
                    return (
                      <CategoryRow key={category.id}>
                        <CategoryThumb>
                          {hasImage ? (
                            <img
                              src={`${CATEGORY_IMAGE_BASE}${category.image_url}`}
                              alt=""
                            />
                          ) : (
                            <CategoryThumbPlaceholder>
                              {initial}
                            </CategoryThumbPlaceholder>
                          )}
                        </CategoryThumb>
                        <CategoryMeta>
                          <CategoryName title={label}>{label}</CategoryName>
                          <CategoryBadges>
                            <PriorityBadge>
                              Priority {category?.priority ?? "—"}
                            </PriorityBadge>
                            {discountNum > 0 && (
                              <DiscountBadge>
                                {discountNum}% off
                              </DiscountBadge>
                            )}
                          </CategoryBadges>
                        </CategoryMeta>
                        <Actions>
                          <Edit
                            aria-label="Edit category"
                            onClick={() => handleOnEdit(category)}
                          />
                          <Delete
                            aria-label="Delete category"
                            onClick={() => {
                              setSelectedIdForAction(category.id);
                              setIsDeletePopupOpen(true);
                            }}
                          />
                        </Actions>
                      </CategoryRow>
                    );
                  })
                ) : (
                  <EmptyState>
                    No categories yet. Add your first category to start building
                    your menu.
                  </EmptyState>
                )}
              </CategoriesContainer>
            </>
          )}
        </>
      )}
    </Container>
  );
}
